<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">and_then</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">v</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> v</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_str</span><span style="color:#9399B2;">())</span></span>
